(function(){'use strict';const G={GEMINI_API_KEY:prompt("Enter your Gemini API Key:"),MODEL:"gemini-2.0-flash",HIGHLIGHT_COLOR:"#ffeb3b",SELECTED_COLOR:"#4caf50",AUTO_SELECT:confirm("Auto-select answers after solving?"),SHOW_REASONING:confirm("Show AI reasoning in console?")};if(!G.GEMINI_API_KEY){alert("❌ No API key provided. Exiting.");return}let questions=[],solutions=[],panel=null;const cleanText=e=>e.replace(/\s+/g," ").trim();function createPanel(){panel=document.createElement("div");panel.id="emaktab-solver-panel";panel.style.cssText="position:fixed;top:20px;right:20px;width:350px;max-height:80vh;background:white;border:2px solid #2196F3;border-radius:10px;padding:15px;box-shadow:0 4px 20px rgba(0,0,0,0.3);z-index:999999;font-family:Arial,sans-serif;overflow-y:auto;color:#333";panel.innerHTML=`\n<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:15px;border-bottom:2px solid #eee;padding-bottom:10px">\n<h3 style="margin:0;color:#2196F3">📝 Emaktab Test Solver</h3>\n<button id="close-panel" style="background:none;border:none;font-size:20px;cursor:pointer">✖</button>\n</div>\n<div id="solver-status" style="margin-bottom:15px;padding:10px;background:#e3f2fd;border-radius:5px">Ready to start. Model: ${G.MODEL}</div>\n<div style="display:flex;gap:10px;margin-bottom:15px;flex-wrap:wrap">\n<button id="extract-questions" style="flex:1;padding:8px;background:#4caf50;color:#fff;border:none;border-radius:5px;cursor:pointer">📋 Extract</button>\n<button id="solve-all" style="flex:1;padding:8px;background:#2196F3;color:#fff;border:none;border-radius:5px;cursor:pointer">🤖 Solve All</button>\n<button id="select-answers" style="flex:1;padding:8px;background:#ff9800;color:#fff;border:none;border-radius:5px;cursor:pointer">🎯 Select</button>\n</div>\n<div style="display:flex;gap:5px;margin-bottom:15px">\n<button id="export-data" style="flex:1;padding:5px;background:#9c27b0;color:#fff;border:none;border-radius:5px;cursor:pointer">📤 Export</button>\n<button id="clear-all" style="flex:1;padding:5px;background:#f44336;color:#fff;border:none;border-radius:5px;cursor:pointer">🗑️ Clear</button>\n</div>\n<div id="questions-list" style="max-height:400px;overflow-y:auto;border:1px solid #ddd;padding:10px;border-radius:5px">No questions extracted yet. Click "Extract" to start.</div>\n<div style="margin-top:15px;font-size:12px;color:#999;text-align:center">Auto-select: ${G.AUTO_SELECT?"✅":"❌"} | Show reasoning: ${G.SHOW_REASONING?"✅":"❌"}</div>`;document.body.appendChild(panel);document.getElementById("close-panel").onclick=()=>panel.remove();document.getElementById("extract-questions").onclick=extractQuestions;document.getElementById("solve-all").onclick=solveAll;document.getElementById("select-answers").onclick=selectAnswers;document.getElementById("export-data").onclick=exportData;document.getElementById("clear-all").onclick=clearAll;document.addEventListener("keydown",e=>{e.ctrlKey&&e.shiftKey&&"E"===e.key&&(e.preventDefault(),extractQuestions())});console.log("✅ Emaktab Solver loaded! Panel created.")}function updateStatus(e,t="info"){const n=document.getElementById("solver-status");if(n){const o={info:"#e3f2fd",success:"#c8e6c9",error:"#ffcdd2",warning:"#fff3e0"};n.style.background=o[t]||o.info;n.innerHTML=e}console.log(`[${t.toUpperCase()}] ${e}`)}function extractQuestions(){questions=[];const e=document.querySelectorAll('[data-test-id^="block-"]');if(0===e.length){updateStatus("❌ No question blocks found!","error");return}updateStatus(`Found ${e.length} question blocks...`,"info");e.forEach((e,t)=>{e.style.outline=`3px solid ${G.HIGHLIGHT_COLOR}`;e.style.outlineOffset="2px";const n=cleanText(e.innerText),o=e.querySelectorAll('[data-test-id^="answer-"]'),l=e.querySelectorAll(".DtVSJ.dbzdF"),s={index:t,block:e,text:n,type:o.length>0?"choice":(l.length>0?"dropdown":"unknown"),options:[],dropdowns:[]};if(o.length>0)o.forEach(e=>{s.options.push({element:e,text:cleanText(e.innerText)})});if(l.length>0)l.forEach(e=>{s.dropdowns.push({element:e,currentValue:cleanText(e.innerText)})});questions.push(s)});renderList();updateStatus(`✅ Extracted ${questions.length} questions`,"success");const t=questions.map(e=>({index:e.index,text:e.text.substring(0,100)+"...",type:e.type,options:e.options.map(e=>e.text),blanks:e.dropdowns.length}));copyToClipboard(JSON.stringify(t,null,2))}function renderList(){const e=document.getElementById("questions-list");if(!e)return;if(0===questions.length){e.innerHTML="No questions extracted yet.";return}let t="";questions.forEach((n,o)=>{const l=solutions.find(e=>e.index===o),s=l?l.solution?"✅":"❌":"⏳";t+=`\n<div style="margin-bottom:15px;padding:10px;background:#f5f5f5;border-radius:5px;border-left:4px solid ${l?"#4caf50":"#ff9800"}">\n<div style="display:flex;justify-content:space-between;margin-bottom:5px">\n<strong>Q${o+1} ${s}</strong>\n<span style="font-size:11px;background:#e0e0e0;padding:2px 5px;border-radius:3px">${n.type}</span>\n</div>\n<div style="font-size:12px;margin-bottom:5px;max-height:60px;overflow:hidden">${n.text.substring(0,100)}...</div>\n${l?`<div style="font-size:11px;background:#e8f5e8;padding:5px;border-radius:3px;margin-bottom:5px"><strong>Solution:</strong> ${l.solution}</div>`:""}\n<button class="solve-single" data-index="${o}" style="margin-right:5px;padding:3px 8px;background:#2196F3;color:#fff;border:none;border-radius:3px;font-size:11px;cursor:pointer">Solve</button>\n<button class="select-single" data-index="${o}" style="padding:3px 8px;background:#ff9800;color:#fff;border:none;border-radius:3px;font-size:11px;cursor:pointer">Select</button>\n</div>`});e.innerHTML=t;document.querySelectorAll(".solve-single").forEach(e=>{e.onclick=()=>solveQuestion(parseInt(e.dataset.index))});document.querySelectorAll(".select-single").forEach(e=>{e.onclick=()=>selectSingle(parseInt(e.dataset.index))})}async function solveQuestion(e){const t=questions[e];if(!t)return;updateStatus(`🤔 Solving question ${e+1}...`,"info");t.block.style.outline="3px solid #ff9800";try{let n="";if("choice"===t.type)n=`You are solving a multiple choice test question. Question: ${t.text} Options:\n${t.options.map((e,t)=>String.fromCharCode(65+t)+". "+e.text).join("\n")}\n\n${G.SHOW_REASONING?"Think step by step. Then":""} Provide ONLY the letter of the correct answer (A, B, C, or D).`;else if("dropdown"===t.type)n=`You are solving a fill-in-the-blanks test question with ${t.dropdowns.length} blanks. Question: ${t.text}\n\n${G.SHOW_REASONING?"Think step by step. Then":""} Provide ONLY the answers as a comma-separated list (e.g., answer1, answer2, answer3).`;else if(t.options.length>0&&t.options[0].text.includes("→")){n=`You are solving a chemistry equation balancing question. ${t.text}\n\nProvide ONLY the complete balanced equation.`}const o=await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${G.MODEL}:generateContent?key=${G.GEMINI_API_KEY}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({contents:[{parts:[{text:n}]}],generationConfig:{temperature:.2,maxOutputTokens:2048}})});if(!o.ok)throw new Error(`HTTP error! status: ${o.status}`);const l=await o.json();if(l.error)throw new Error(l.error.message);let s="";if(l.candidates&&l.candidates[0]&&l.candidates[0].content&&l.candidates[0].content.parts&&l.candidates[0].content.parts[0]){s=l.candidates[0].content.parts[0].text}else{console.error("Unexpected API response:",l);throw new Error("Invalid API response structure")}if("choice"===t.type){const e=s.match(/\b([A-D])\b/);e&&(s=e[1])}solutions=solutions.filter(n=>n.index!==e);solutions.push({index:e,type:t.type,solution:s,fullResponse:s,timestamp:new Date().toISOString()});t.block.style.outline=`3px solid ${G.SELECTED_COLOR}`;updateStatus(`✅ Question ${e+1} solved!`,"success");G.SHOW_REASONING&&console.log(`📝 Reasoning for Q${e+1}:`,s);G.AUTO_SELECT&&await selectSingle(e);renderList()}catch(n){updateStatus(`❌ Error: ${n.message}`,"error");t.block.style.outline="3px solid #f44336";console.error("Full error:",n)}}async function solveAll(){updateStatus(`🔄 Solving ${questions.length} questions...`,"info");for(let e=0;e<questions.length;e++)await solveQuestion(e),await new Promise(e=>setTimeout(e,1500));updateStatus("✅ All questions solved!","success")}async function selectSingle(e){const t=questions[e],n=solutions.find(n=>n.index===e);if(!t||!n){updateStatus(`❌ No solution for question ${e+1}`,"error");return}if("choice"===t.type){const o=n.solution.toUpperCase(),l=o.charCodeAt(0)-65;l>=0&&l<t.options.length&&(t.options[l].element.click(),t.options[l].element.style.outline=`3px solid ${G.SELECTED_COLOR}`,t.options[l].element.style.backgroundColor="#e8f5e8",updateStatus(`✅ Selected option ${o} for Q${e+1}`,"success"))}else if("dropdown"===t.type){const o=n.solution.split(",").map(e=>e.trim());for(let n=0;n<Math.min(o.length,t.dropdowns.length);n++){const l=o[n],s=t.dropdowns[n].element;s.click(),await new Promise(e=>setTimeout(e,300));const a=Array.from(document.querySelectorAll('[role="option"], .dropdown-option, li')).find(e=>e.textContent.includes(l));a?a.click():document.dispatchEvent(new KeyboardEvent("keydown",{key:"Escape"}));await new Promise(e=>setTimeout(e,200))}}else{console.log(`Question ${e+1} type not supported for auto-select`)}}async function selectAnswers(){updateStatus("🎯 Selecting answers...","info");for(let e=0;e<questions.length;e++)await selectSingle(e);updateStatus("✅ Answer selection complete!","success")}function exportData(){const e={timestamp:new Date().toISOString(),questions:questions.map(e=>({index:e.index,text:e.text,type:e.type,options:e.options.map(e=>e.text),blanks:e.dropdowns.length})),solutions:solutions};copyToClipboard(JSON.stringify(e,null,2));updateStatus("📋 Data copied to clipboard!","success")}function clearAll(){questions=[];solutions=[];document.querySelectorAll('[style*="outline"]').forEach(e=>{e.style.outline="",e.style.backgroundColor=""});renderList();updateStatus("🧹 All cleared","info")}function copyToClipboard(e){const t=document.createElement("textarea");t.value=e;document.body.appendChild(t);t.select();document.execCommand("copy");document.body.removeChild(t)}console.log("\n╔════════════════════════════════════╗\n║  EMAKTAB TEST SOLVER LOADED!       ║\n║  Look for the blue panel on the     ║\n║  right side of the page.            ║\n║  Press Ctrl+Shift+E to extract      ║\n╚════════════════════════════════════╝");createPanel()})();
